import random
from dataclasses import dataclass


@dataclass
class SlipperyFloorEnvironment:
    """
    A stochastic grid world where the robot sometimes slips.
    Intended action succeeds with probability p_success;
    otherwise a random perpendicular direction is applied.
    """

    grid: list[list[str]]
    p_success: float = 0.8    # intended action applies 80% of the time

    _DELTAS = {"up": (-1, 0), "down": (1, 0), "left": (0, -1), "right": (0, 1)}
    _PERP = {
        "up":    ["left", "right"],
        "down":  ["left", "right"],
        "left":  ["up", "down"],
        "right": ["up", "down"],
    }

    def step(self, pos: tuple[int, int], action: str) -> tuple[int, int]:
        """Apply action with stochastic slip."""
        if random.random() < self.p_success:
            effective = action
        else:
            effective = random.choice(self._PERP[action])  # slip!

        dr, dc = self._DELTAS[effective]
        nr, nc = pos[0] + dr, pos[1] + dc
        rows, cols = len(self.grid), len(self.grid[0])
        if 0 <= nr < rows and 0 <= nc < cols and self.grid[nr][nc] != "#":
            return (nr, nc)
        return pos


env = SlipperyFloorEnvironment(
    grid=[[".", ".", "."], [".", ".", "."], [".", ".", "."]],
    p_success=0.8,
)

# Same action from same position can yield different results
random.seed(0)
outcomes = [env.step((1, 1), "up") for _ in range(5)]
print(outcomes)  # mix of (0,1), (1,0), (1,2) — not always (0,1)

from dataclasses import dataclass, field
import math


@dataclass
class StochasticAgent:
    """
    An agent that models action outcomes as probability distributions
    and picks the action with the highest expected utility.
    """

    # outcome_model[action][outcome] = probability
    outcome_model: dict[str, dict[tuple, float]] = field(default_factory=dict)
    # utility[state] = reward value
    utility: dict[tuple, float] = field(default_factory=dict)

    def expected_utility(self, action: str) -> float:
        """E[U(action)] = sum_s P(s | action) * U(s)."""
        if action not in self.outcome_model:
            return -math.inf
        return sum(
            prob * self.utility.get(outcome, 0.0)
            for outcome, prob in self.outcome_model[action].items()
        )

    def act(self) -> str:
        """Choose the action with the maximum expected utility."""
        return max(self.outcome_model, key=self.expected_utility)


# Example: robot at (1,1) choosing between "up" and "right"
# "up" usually reaches goal (2.0) but might slip into a trap (-1.0)
# "right" reliably reaches a mediocre cell (0.5)
agent = StochasticAgent(
    outcome_model={
        "up":    {(0, 1): 0.8, (1, 0): 0.1, (1, 2): 0.1},   # goal / slip_left / slip_right
        "right": {(1, 2): 1.0},
    },
    utility={(0, 1): 2.0, (1, 0): -1.0, (1, 2): 0.5},
)
print(agent.expected_utility("up"))    # 0.8*2.0 + 0.1*(-1.0) + 0.1*0.5 = 1.45
print(agent.expected_utility("right")) # 1.0*0.5 = 0.5
print(agent.act())                     # "up" — higher expected utility

from dataclasses import dataclass, field


@dataclass
class MDP:
    """
    Markov Decision Process — the formal model for stochastic sequential decision-making.
    Components: States S, Actions A, Transition T, Reward R, Discount gamma.
    """

    states: list
    actions: list
    # T[state][action] = {next_state: probability}
    transition: dict[any, dict[str, dict[any, float]]]
    # R[state][action] = immediate reward
    reward: dict[any, dict[str, float]]
    gamma: float = 0.9  # discount factor

    def value_iteration(self, iterations: int = 100) -> dict:
        """
        Compute the optimal value function V*(s) via value iteration.
        V*(s) = max_a [ R(s,a) + gamma * sum_{s'} T(s,a,s') * V*(s') ]
        """
        V = {s: 0.0 for s in self.states}
        for _ in range(iterations):
            V_new = {}
            for s in self.states:
                best = max(
                    self.reward[s][a] + self.gamma * sum(
                        prob * V[ns]
                        for ns, prob in self.transition[s][a].items()
                    )
                    for a in self.actions
                )
                V_new[s] = best
            V = V_new
        return V

    def extract_policy(self, V: dict) -> dict:
        """Extract greedy policy from value function."""
        policy = {}
        for s in self.states:
            policy[s] = max(
                self.actions,
                key=lambda a: (
                    self.reward[s][a] + self.gamma * sum(
                        prob * V[ns]
                        for ns, prob in self.transition[s][a].items()
                    )
                )
            )
        return policy


# Small 3-state MDP: states A, B (goal), C (trap)
mdp = MDP(
    states=["A", "B", "C"],
    actions=["left", "right"],
    transition={
        "A": {
            "right": {"B": 0.8, "C": 0.2},   # slip may hit trap
            "left":  {"A": 1.0},              # wall: stay put
        },
        "B": {"right": {"B": 1.0}, "left": {"B": 1.0}},  # absorbing
        "C": {"right": {"C": 1.0}, "left": {"C": 1.0}},  # absorbing
    },
    reward={
        "A": {"right": 0.0, "left": 0.0},
        "B": {"right": 1.0, "left": 1.0},
        "C": {"right": -5.0, "left": -5.0},
    },
)
V = mdp.value_iteration()
policy = mdp.extract_policy(V)
print(V)       # {"A": ~5.8, "B": ~10.0, "C": ~-50.0}
print(policy)  # {"A": "right", "B": "right", "C": "right"}
# Agent prefers "right" from A despite 20% trap risk — expected reward is positive

import pytest
import random


class TestStochasticEnvironment:
    def test_outcomes_are_in_valid_states(self):
        env = SlipperyFloorEnvironment(
            grid=[[".", ".", "."], [".", ".", "."], [".", ".", "."]],
            p_success=0.8,
        )
        for _ in range(50):
            next_pos = env.step((1, 1), "up")
            assert next_pos in {(0, 1), (1, 0), (1, 2)}

    def test_success_probability_is_approximately_correct(self):
        random.seed(42)
        env = SlipperyFloorEnvironment(
            grid=[[".", ".", "."], [".", ".", "."], [".", ".", "."]],
            p_success=0.8,
        )
        intended = sum(
            1 for _ in range(1000) if env.step((1, 1), "up") == (0, 1)
        )
        # Should be ~800/1000; allow tolerance
        assert 750 <= intended <= 850


class TestStochasticAgent:
    def test_agent_picks_higher_expected_utility_action(self):
        agent = StochasticAgent(
            outcome_model={
                "safe":  {"goal": 1.0},
                "risky": {"goal": 0.5, "trap": 0.5},
            },
            utility={"goal": 2.0, "trap": -10.0},
        )
        # EU(safe) = 2.0, EU(risky) = 0.5*2.0 + 0.5*(-10.0) = -4.0
        assert agent.act() == "safe"

# Pitfall: treating a stochastic environment as deterministic

class DeterministicPlannerInStochasticWorld:
    """Plans as if actions always succeed — breaks when they don't."""

    def __init__(self, goal_state):
        self.goal = goal_state
        self.plan: list[str] = []

    def replan(self, state) -> str:
        """Generate a fixed-sequence plan without considering slip probability."""
        if state == self.goal:
            return "done"
        # Hard-codes "go right" regardless of whether that actually works
        return "right"


# The problem: after a slip the agent is in the wrong state,
# but the plan doesn't account for it. The agent keeps issuing
# "right" commands while drifting further from the goal.

# Fix: use a reactive policy (state → action map) instead of a plan,
# so the correct action is always looked up from the CURRENT state,
# not from where the agent expected to be.

class ReactivePolicyAgent:
    """Looks up the optimal action for the CURRENT state at each step."""

    def __init__(self, policy: dict):
        self.policy = policy

    def act(self, current_state) -> str:
        return self.policy.get(current_state, "idle")
